def calculate(self, s: str) -> int:
    stack = []
    result = 0
    for char in s:
        if char in ['+', '-', '*', '/']:
            num1 = stack.pop()
            num2 = stack.pop()
            if char == '+':
                result = num1 + num2
            elif char == '-':
                result = num1 - num2
            elif char == '*':
                result = num1 * num2
            elif char == '/':
                if num2 == 0:
                raise ValueError("Cannot divide by zero")
                result = num1 // num2
        else:
            stack.append(int(char))
    return result

